func ObservacionesEqualFold(v string) predicate.ServicioMedicion {
	return predicate.ServicioMedicion(sql.FieldEqualFold(FieldObservaciones, v))
}

// ObservacionesContainsFold applies the ContainsFold predicate on the "observaciones" field.
func ObservacionesContainsFold(v string) predicate.ServicioMedicion {
	return predicate.ServicioMedicion(sql.FieldContainsFold(FieldObservaciones, v))
}

// HasUnidad applies the HasEdge predicate on the "unidad" edge.
func HasUnidad() predicate.ServicioMedicion {
	return predicate.ServicioMedicion(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, UnidadTable, UnidadColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasUnidadWith applies the HasEdge predicate on the "unidad" edge with a given conditions (other predicates).
func HasUnidadWith(preds ...predicate.Unidad) predicate.ServicioMedicion {
	return predicate.ServicioMedicion(func(s *sql.Selector) {
		step := newUnidadStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ServicioMedicion) predicate.ServicioMedicion {
	return predicate.ServicioMedicion(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ServicioMedicion) predicate.ServicioMedicion {
	return predicate.ServicioMedicion(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ServicioMedicion) predicate.ServicioMedicion {
	return predicate.ServicioMedicion(sql.NotPredicates(p))
}
